{
    //
    // Check the arguments.
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Write to FREE_SOFT bits
    //
    HWREG(base + MCPWM_O_TBCTL) =
           ((HWREGH(base + MCPWM_O_TBCTL) & (~MCPWM_TBCTL_FREE_SOFT_M)) |
            ((uint32_t)emulationMode << MCPWM_TBCTL_FREE_SOFT_S));
}

{
    float32_t tbClkInHz = 0.0F;
    uint16_t tbPrdVal = 0U;
    uint16_t cmp1AVal = 0U, cmp1BVal = 0U;
    uint16_t cmp2AVal = 0U, cmp2BVal = 0U;
    uint16_t cmp3AVal = 0U, cmp3BVal = 0U;

    //
    // Check the arguments.
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Valid values in the function for TBCTR Mode are UP, DOWN
    // and UP-DOWN count.
    //
    ASSERT((uint16_t)signalParams->tbCtrMode < 2U);

    //
    // Configure Time Base counter Clock
    //
    MCPWM_setClockPrescaler(base, signalParams->tbClkDiv);

    //
    // Configure Time Base Counter Mode
    //
    MCPWM_setTimeBaseCounterMode(base, signalParams->tbCtrMode);

    //
    // Calculate TBCLK, TBPRD and CMPx values to be configured for
    // achieving desired signal
    //
    tbClkInHz = ((float32_t)signalParams->sysClkInHz /
                 (float32_t)(1U << ((uint16_t)signalParams->tbClkDiv)));

    if(signalParams->tbCtrMode == MCPWM_COUNTER_MODE_UP)
    {
        tbPrdVal = (uint16_t)((tbClkInHz / signalParams->freqInHz) - 1.0f);
        cmp1AVal = (uint16_t)(signalParams->dutyVal1A *
                             (float32_t)(tbPrdVal + 1U));
        cmp1BVal = (uint16_t)(signalParams->dutyVal1B *
                             (float32_t)(tbPrdVal + 1U));

        cmp2AVal = (uint16_t)(signalParams->dutyVal2A *
                             (float32_t)(tbPrdVal + 1U));
        cmp2BVal = (uint16_t)(signalParams->dutyVal2B *
                             (float32_t)(tbPrdVal + 1U));

        cmp3AVal = (uint16_t)(signalParams->dutyVal3A *
                             (float32_t)(tbPrdVal + 1U));
        cmp3BVal = (uint16_t)(signalParams->dutyVal3B *
                             (float32_t)(tbPrdVal + 1U));
    }
    else
    {
        tbPrdVal = (uint16_t)(tbClkInHz / (2.0f * signalParams->freqInHz));
        cmp1AVal = (uint16_t)(((float32_t)tbPrdVal -
                             ((signalParams->dutyVal1A *
                              (float32_t)tbPrdVal))) + 0.5f);
        cmp1BVal = (uint16_t)(((float32_t)tbPrdVal -
                             ((signalParams->dutyVal1B *
                              (float32_t)tbPrdVal))) + 0.5f);
        cmp2AVal = (uint16_t)(((float32_t)tbPrdVal -
                             ((signalParams->dutyVal2A *
                              (float32_t)tbPrdVal))) + 0.5f);
        cmp2BVal = (uint16_t)(((float32_t)tbPrdVal -
                             ((signalParams->dutyVal2B *
                              (float32_t)tbPrdVal))) + 0.5f);
        cmp3AVal = (uint16_t)(((float32_t)tbPrdVal -
                             ((signalParams->dutyVal3A *
                              (float32_t)tbPrdVal))) + 0.5f);
        cmp3BVal = (uint16_t)(((float32_t)tbPrdVal -
                             ((signalParams->dutyVal3B *
                              (float32_t)tbPrdVal))) + 0.5f);

    }

    //
    // Configure TBPRD value
    //
    MCPWM_setTimeBasePeriodShadow(base, tbPrdVal);

    //
    // Default Configurations.
    //
    MCPWM_disablePhaseShiftLoad(base);
    MCPWM_setPhaseShift(base, 0U);
    MCPWM_setTimeBaseCounter(base, 0U);

    //
    // Setup shadow register load on ZERO
    //
    MCPWM_setCounterCompareShadowLoadMode(base,
                                         MCPWM_COUNTER_COMPARE_1A,
                                         MCPWM_COMP_LOAD_ON_CNTR_ZERO);
    MCPWM_setCounterCompareShadowLoadMode(base,
                                         MCPWM_COUNTER_COMPARE_1B,
                                         MCPWM_COMP_LOAD_ON_CNTR_ZERO);
    MCPWM_setCounterCompareShadowLoadMode(base,
                                         MCPWM_COUNTER_COMPARE_2A,
                                         MCPWM_COMP_LOAD_ON_CNTR_ZERO);
    MCPWM_setCounterCompareShadowLoadMode(base,
                                         MCPWM_COUNTER_COMPARE_2B,
                                         MCPWM_COMP_LOAD_ON_CNTR_ZERO);
    MCPWM_setCounterCompareShadowLoadMode(base,
                                         MCPWM_COUNTER_COMPARE_3A,
                                         MCPWM_COMP_LOAD_ON_CNTR_ZERO);
    MCPWM_setCounterCompareShadowLoadMode(base,
                                         MCPWM_COUNTER_COMPARE_3B,
                                         MCPWM_COMP_LOAD_ON_CNTR_ZERO);
    //
    // Set Compare values
    //
    MCPWM_setCounterCompareShadowValue(base, MCPWM_COUNTER_COMPARE_1A,
                                cmp1AVal);
    MCPWM_setCounterCompareShadowValue(base, MCPWM_COUNTER_COMPARE_1B,
                                cmp1BVal);
    MCPWM_setCounterCompareShadowValue(base, MCPWM_COUNTER_COMPARE_2A,
                                cmp2AVal);
    MCPWM_setCounterCompareShadowValue(base, MCPWM_COUNTER_COMPARE_2B,
                                cmp2BVal);
    MCPWM_setCounterCompareShadowValue(base, MCPWM_COUNTER_COMPARE_3A,
                                cmp3AVal);
    MCPWM_setCounterCompareShadowValue(base, MCPWM_COUNTER_COMPARE_3B,
                                cmp3BVal);

    //
    // Set actions for mcpwmxA & mcpwmxB
    //
    if(signalParams->tbCtrMode == MCPWM_COUNTER_MODE_UP)
    {
        //
        // Set on Zero, clear on CMPA 
        //
        MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_1A,
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_ZERO | (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPA);
        MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_2A,
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_ZERO | (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPA);
        MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_3A,
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_ZERO | (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPA);

        if(signalParams->invertSignal1B == (bool) true)
        {
            //
            // Clear PWMxB on Zero and set on CMPB 
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_1B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_ZERO | (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPB);

        }
        else
        {
            //
            // Set PWMxB on Zero and clear on CMPB 
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_1B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_ZERO | (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPB);
        }
        if(signalParams->invertSignal2B == (bool) true)
        {
            //
            // Clear PWMxB on Zero and set on CMPB 
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_2B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_ZERO | (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPB);

        }
        else
        {
            //
            // Set PWMxB on Zero and clear on CMPB 
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_2B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_ZERO | (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPB);
        }
        if(signalParams->invertSignal3B == (bool) true)
        {
            //
            // Clear PWMxB on Zero and set on CMPB 
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_3B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_ZERO | (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPB);

        }
        else
        {
            //
            // Set PWMxB on Zero and clear on CMPB 
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_3B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_ZERO | (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPB);
        }
    }
    else
    {
        //
        // Clear PWMxA on Zero set on CMPA up, and clear on CMPA down
        //
        MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_1A,
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_ZERO | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPA | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_DOWN_CMPA);
        MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_2A,
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_ZERO | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPA | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_DOWN_CMPA);
        MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_3A,
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_ZERO | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPA | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_DOWN_CMPA);

        if(signalParams->invertSignal1B == (bool) true)
        {
            //
            // Set PWMxB on Zero, clear on CMPA up and Set on CMPB down
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_1B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_ZERO | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPB |
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPB);
        }
        else
        {
            //
            // clear PWMxB on Zero, Set on CMPA up and clear on CMPB down
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_1B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_ZERO | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPB |
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPB);
        }
        if(signalParams->invertSignal2B == (bool) true)
        {
            //
            // Set PWMxB on Zero, clear on CMPA up and Set on CMPB down
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_2B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_ZERO | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPB |
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPB);
        }
        else
        {
            //
            // clear PWMxB on Zero, Set on CMPA up and clear on CMPB down
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_2B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_ZERO | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPB |
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPB);
        }
        if(signalParams->invertSignal3B == (bool) true)
        {
            //
            // Set PWMxB on Zero, clear on CMPA up and Set on CMPB down
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_3B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_ZERO | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPB |
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPB);
        }
        else
        {
            //
            // clear PWMxB on Zero, Set on CMPA up and clear on CMPB down
            //
            MCPWM_setActionQualifierActionCompleteShadow(base, MCPWM_AQ_OUTPUT_3B,
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_ZERO | 
                                 (uint16_t)MCPWM_AQ_OUTPUT_HIGH_UP_CMPB |
                                 (uint16_t)MCPWM_AQ_OUTPUT_LOW_UP_CMPB);
        }

    }
}

{
    return(
           (base == PWM1_BASE) ||
           (base == PWM3_BASE)
          );
}

{
    //
    // Check the arguments.
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Get the revision value.
    //
    return(HWREG(base + MCPWM_O_REVISION));
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Write to TBPHS bit
    //
    HWREG(base + MCPWM_O_TBPHS) =
                   ((HWREG(base + MCPWM_O_TBPHS) &
                    ~((uint32_t)MCPWM_TBPHS_TBPHS_M)) |
                    ((uint32_t)phaseCount << MCPWM_TBPHS_TBPHS_S));
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Write to TBCTR register
    //
    HWREG(base + MCPWM_O_TBCTR) = count;
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Returns TBCTR value
    //
    return((uint16_t)HWREG(base + MCPWM_O_TBCTR));
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Write to CTRMODE bit
    //
    HWREG(base + MCPWM_O_TBCTL) =
            ((HWREG(base + MCPWM_O_TBCTL) & ~(MCPWM_TBCTL_CTRMODE_M)) |
             ((uint32_t)counterMode));
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Return CTRDIR bit
    //
    return(HWREG(base + MCPWM_O_TBSTS) & MCPWM_TBSTS_CTRDIR);
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Write to CLKDIV bit
    //
    HWREG(base + MCPWM_O_TBCTL) =
                ((HWREG(base + MCPWM_O_TBCTL)  &
                ~MCPWM_TBCTL_CLKDIV_M) |
                ((uint16_t)prescaler << MCPWM_TBCTL_CLKDIV_S));
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    if(loadMode == MCPWM_PERIOD_SHADOW_LOAD_ENABLE)
    {
        //
        // Clear PRDLD
        //
        HWREG(base + MCPWM_O_TBCTL) &= ~MCPWM_TBCTL_PRDLD;
    }
    else
    {
        //
        // Set PRDLD
        //
        HWREG(base + MCPWM_O_TBCTL) |= MCPWM_TBCTL_PRDLD;
    }
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Set PHSEN bit
    //
    HWREG(base + MCPWM_O_TBCTL) |= MCPWM_TBCTL_PHSEN;
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Clear PHSEN bit
    //
    HWREG(base + MCPWM_O_TBCTL) &= ~((uint32_t)MCPWM_TBCTL_PHSEN);
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    if(mode == MCPWM_COUNT_MODE_UP_AFTER_SYNC)
    {
        //
        // Set PHSDIR bit
        //
        HWREG(base + MCPWM_O_TBCTL) |= MCPWM_TBCTL_PHSDIR;
    }
    else
    {
        //
        // Clear PHSDIR bit
        //
        HWREG(base + MCPWM_O_TBCTL) &= ~MCPWM_TBCTL_PHSDIR;
    }
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Set SWFSYNC bit
    //
    HWREG(base + MCPWM_O_TBCTL) |= MCPWM_TBCTL_SWSYNC;
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // No extended mode support
    //
    if(mode < MCPWM_SYNC_OUT_PULSE_DISABLED)
    {
        //
        // Write to SYNCOSEL bits
        //
        HWREG(base + MCPWM_O_TBCTL) =
                ((HWREG(base + MCPWM_O_TBCTL) & ~(MCPWM_TBCTL_SYNCOSEL_M)) |
                 ((uint32_t)mode << MCPWM_TBCTL_SYNCOSEL_S));
    }
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Set the SYNCPERSEL source
    //
    HWREG(base + MCPWM_O_TBCTL) =
                ((HWREG(base + MCPWM_O_TBCTL) & ~(MCPWM_TBCTL_SYNCPERSEL_M)) |
                 ((uint32_t)syncPulseSource << MCPWM_TBCTL_SYNCPERSEL_S));

}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Set MCPWM Sync-In Source Mode.
    //
    HWREG(base + MCPWM_O_TBCTL) =
            (HWREG(base + MCPWM_O_TBCTL) & (~MCPWM_TBCTL_SYNCISEL_M)) |
            (((uint32_t)source << MCPWM_TBCTL_SYNCISEL_S));
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Return TRUE if SYNCI bit is set, FALSE otherwise
    //
    return(((HWREG(base + MCPWM_O_TBSTS) & MCPWM_TBSTS_SYNCI) ==
            MCPWM_TBSTS_SYNCI) ? TRUE : FALSE);
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Set SYNCI bit
    //
    HWREGH(base + MCPWM_O_TBSTSCLR) = MCPWM_TBSTS_SYNCI;
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Write to TBPRD bit
    //
    HWREG(base + MCPWM_O_TBPRD) = periodCount;
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Write to TBPRD bit
    //
    HWREG(base + MCPWM_O_TBPRDS) = periodCount;
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Read from TBPRD bit
    //
    return( (uint16_t) HWREG(base + MCPWM_O_TBPRD) & MCPWM_TBPRD_TBPRD_M);
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Read from TBPRD bit
    //
    return( (uint16_t) HWREG(base + MCPWM_O_TBPRDS) & MCPWM_TBPRDS_TBPRDS_M);
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Write to the counter compare registers.
    //
    switch (compModule)
    {
    case MCPWM_COUNTER_COMPARE_1A:
        HWREGH(base + MCPWM_O_PWM1_CMPA) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_1B:
        HWREGH(base + MCPWM_O_PWM1_CMPB) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_2A:
        HWREGH(base + MCPWM_O_PWM2_CMPA) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_2B:
        HWREGH(base + MCPWM_O_PWM2_CMPB) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_3A:
        HWREGH(base + MCPWM_O_PWM3_CMPA) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_3B:
        HWREGH(base + MCPWM_O_PWM3_CMPB) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_C:
        HWREGH(base + MCPWM_O_CMPC) = compCount; 
        break;
    default:
        HWREGH(base + MCPWM_O_CMPD) = compCount; 
        break;    
    }
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    uint16_t retValue = 0;

    //
    // Write to the counter compare registers.
    //
    switch (compModule)
    {
    case MCPWM_COUNTER_COMPARE_1A:
        retValue = (HWREGH(base + MCPWM_O_PWM1_CMPA)); 
        break;
    case MCPWM_COUNTER_COMPARE_1B:
        retValue = (HWREGH(base + MCPWM_O_PWM1_CMPB)); 
        break;
    case MCPWM_COUNTER_COMPARE_2A:
        retValue = (HWREGH(base + MCPWM_O_PWM2_CMPA)); 
        break;
    case MCPWM_COUNTER_COMPARE_2B:
        retValue = (HWREGH(base + MCPWM_O_PWM2_CMPB)); 
        break;
    case MCPWM_COUNTER_COMPARE_3A:
        retValue = (HWREGH(base + MCPWM_O_PWM3_CMPA)); 
        break;
    case MCPWM_COUNTER_COMPARE_3B:
        retValue = (HWREGH(base + MCPWM_O_PWM3_CMPB)); 
        break;
    case MCPWM_COUNTER_COMPARE_C:
        retValue = (HWREGH(base + MCPWM_O_CMPC)); 
        break;
    default:
        retValue = (HWREGH(base + MCPWM_O_CMPD)); 
        break;
    }
        return retValue;
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));

    //
    // Write to the counter compare registers.
    //
    switch (compModule)
    {
    case MCPWM_COUNTER_COMPARE_1A:
        HWREGH(base + MCPWM_O_PWM1_CMPAS) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_1B:
        HWREGH(base + MCPWM_O_PWM1_CMPBS) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_2A:
        HWREGH(base + MCPWM_O_PWM2_CMPAS) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_2B:
        HWREGH(base + MCPWM_O_PWM2_CMPBS) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_3A:
        HWREGH(base + MCPWM_O_PWM3_CMPAS) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_3B:
        HWREGH(base + MCPWM_O_PWM3_CMPBS) = compCount; 
        break;
    case MCPWM_COUNTER_COMPARE_C:
        HWREGH(base + MCPWM_O_CMPCS) = compCount; 
        break;
    default:
        HWREGH(base + MCPWM_O_CMPDS) = compCount; 
        break;    
    }
}

{
    //
    // Check the arguments
    //
    ASSERT(MCPWM_isBaseValid(base));
    uint16_t retValue =0;
    //
    // Write to the counter compare registers.
    //
    switch (compModule)
    {
    case MCPWM_COUNTER_COMPARE_1A:
        retValue =  (HWREGH(base + MCPWM_O_PWM1_CMPAS)); 
        break;
    case MCPWM_COUNTER_COMPARE_1B:
        retValue =  (HWREGH(base + MCPWM_O_PWM1_CMPBS)); 
        break;
    case MCPWM_COUNTER_COMPARE_2A:
        retValue =  (HWREGH(base + MCPWM_O_PWM2_CMPAS)); 
        break;
    case MCPWM_COUNTER_COMPARE_2B:
        retValue =  (HWREGH(base + MCPWM_O_PWM2_CMPBS)); 
        break;
    case MCPWM_COUNTER_COMPARE_3A:
        retValue =  (HWREGH(base + MCPWM_O_PWM3_CMPAS)); 
        break;
    case MCPWM_COUNTER_COMPARE_3B:
        retValue =  (HWREGH(base + MCPWM_O_PWM3_CMPBS)); 
        break;
    case MCPWM_COUNTER_COMPARE_C:
        retValue =  (HWREGH(base + MCPWM_O_CMPCS)); 
        break;
    default:
        retValue =  (HWREGH(base + MCPWM_O_CMPDS)); 
        break;    
    }

    return retValue;
}

